class Solution:
    def maxPoints(self, points):
        n = len(points)
        if n <= 2:
            return n
        best = 1
        for i in range(n):
            for j in range(i + 1, n):
                ax, ay = points[i]
                bx, by = points[j]
                cnt = 2
                for k in range(n):
                    if k == i or k == j:
                        continue
                    cx, cy = points[k]
                    if (bx - ax) * (cy - ay) - (by - ay) * (cx - ax) == 0:
                        cnt += 1
                best = max(best, cnt)
        return best

