class Solution:
    def maxPoints(self, points):
        from math import gcd
        n = len(points)
        if n <= 2:
            return n
        best = 1
        for i in range(n):
            slopes = {}
            ax, ay = points[i]
            for j in range(n):
                if j == i:
                    continue
                dx = points[j][0] - ax
                dy = points[j][1] - ay
                g = gcd(dx, dy)
                if g != 0:
                    dx //= g
                    dy //= g
                if dx < 0 or (dx == 0 and dy < 0):
                    dx, dy = -dx, -dy
                key = (dx, dy)
                slopes[key] = slopes.get(key, 0) + 1
            local = max(slopes.values()) + 1
            best = max(best, local)
        return best

