var maxPoints = function(points) {
    const n = points.length;
    if (n <= 2) return n;
    const gcd = (a, b) => { a = Math.abs(a); b = Math.abs(b); while (b) { [a, b] = [b, a % b]; } return a; };
    let best = 1;
    for (let i = 0; i < n; i++) {
        const slopes = new Map();
        const ax = points[i][0], ay = points[i][1];
        for (let j = 0; j < n; j++) {
            if (j === i) continue;
            let dx = points[j][0] - ax;
            let dy = points[j][1] - ay;
            const g = gcd(dx, dy);
            if (g !== 0) { dx = Math.trunc(dx / g); dy = Math.trunc(dy / g); }
            if (dx < 0 || (dx === 0 && dy < 0)) { dx = -dx; dy = -dy; }
            const key = dx + ',' + dy;
            slopes.set(key, (slopes.get(key) || 0) + 1);
        }
        let local = 0;
        for (const v of slopes.values()) local = Math.max(local, v);
        best = Math.max(best, local + 1);
    }
    return best;
};
